def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    in_degree = [0] * n
    for u, v, cost in edges:
        adj[u].append((v, cost))
        in_degree[v] += 1

    # Compute topological order
    queue = deque()
    for i in range(n):
        if in_degree[i] == 0:
            queue.append(i)
    topological_order = []
